//! M5-06 T14 — `wfst_decode` numerical parity against real OpenFST.
//!
//! Verifies Vokra's from-scratch WFST decoder against fixtures generated by the
//! **real OpenFST** CLI (`tools/parity/wfst_dump_reference.py`, the independent
//! oracle — a self-computed reference would verify nothing, per the
//! numerical-parity discipline). The committed fixtures live in
//! `tests/parity/fixtures/m5-06/`; this test reads them and needs no OpenFST,
//! so CI runs it without the OpenFST toolchain.
//!
//! For each fixture it asserts:
//!   (a) the reader reconstructs the OpenFST binary's structure exactly
//!       (start / num_states / finals / arcs), so the byte parser is verified
//!       against a real producer (T06);
//!   (b) the decoded best-path **output (word) sequence is an EXACT match**
//!       (tropical Viterbi is argmax-deterministic);
//!   (c) the best-path **score** is within an honest tolerance — the float
//!       accumulation bound, NOT a value tuned to pass (see [`SCORE_ATOL`]);
//!   (d) the n-best set matches (same word sequences, best-first, scores in
//!       tolerance).
//!
//! # This file is feature-gated (`vokra-wfst`)
//!
//! The `#![cfg(feature = "vokra-wfst")]` below means **without the feature this
//! file compiles to zero tests**. That is deliberate (the decoder module is
//! opt-in), but it also means a CI leg that forgets `--features vokra-wfst`
//! would be a vacuous green — a fabricated pass. The CI job (M5-06 T15) runs
//! `cargo test -p vokra-core --test parity_wfst --features vokra-wfst` with the
//! flag written literally for exactly this reason.

#![cfg(feature = "vokra-wfst")]

use std::path::PathBuf;
use std::str::FromStr;

use vokra_core::decode::wfst::{WfstDecoder, read_openfst_vector};

/// Honest score tolerance for best-path / n-best costs (NFR-QL-01).
///
/// The path cost is a tropical sum (`⊗ = +`) of a handful of f32 terms; the
/// only difference between Vokra's decoder and OpenFST's `shortestpath` is the
/// **accumulation order** (both consume the *same* f32 emission values and the
/// *same* f32 arc weights from the committed fixture). For a sum of ~5 terms of
/// magnitude ~1, the worst-case f32 round-off is ~5 × 0.5 ulp(1.0) ≈
/// 5 × 6e-8 ≈ 3e-7, and two different orders differ by up to ~2× that ≈ 6e-7.
/// So the architectural bound is ~6e-7; this tolerance is ~1.6× that. The test
/// prints the measured max delta (`WFST_SCORE_DELTA`) so any regression that
/// approaches the bound is visible — it is **not** a knob to loosen for a
/// green CI (feedback-honest-parity-atol).
const SCORE_ATOL: f64 = 1.0e-6;

/// Tolerance for reader-vs-OpenFST structure weights (final / arc). These are
/// the *same* stored f32 read two ways (Vokra bytes vs OpenFST `fstprint`
/// decimal); the round-trip is near-exact, this is just slack for the decimal
/// re-parse.
const STRUCT_ATOL: f64 = 1.0e-6;

fn fixtures_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("parity")
        .join("fixtures")
        .join("m5-06")
}

/// A parsed `.expected` fixture (mirrors the dumper's writer).
struct Expected {
    graph_file: String,
    start: u32,
    num_states: usize,
    finals: Vec<(u32, f32)>,
    arcs: Vec<(u32, u32, u32, f32, u32)>, // (src, ilabel, olabel, weight, dst)
    emission: Vec<Vec<f32>>,
    best: (f32, Vec<u32>),       // (score, words)
    nbest: Vec<(f32, Vec<u32>)>, // best-first
}

fn pf32(s: &str) -> f32 {
    f32::from_str(s).unwrap_or_else(|_| panic!("bad f32 `{s}`"))
}

fn parse_expected(text: &str) -> Expected {
    let mut graph_file = String::new();
    let mut start = 0u32;
    let mut num_states = 0usize;
    let mut finals = Vec::new();
    let mut arcs = Vec::new();
    let mut emission: Vec<Vec<f32>> = Vec::new();
    let mut best = (0.0f32, Vec::new());
    let mut nbest = Vec::new();

    for line in text.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let t: Vec<&str> = line.split_whitespace().collect();
        match t[0] {
            "VERSION" => assert_eq!(t[1], "1", "unexpected fixture VERSION"),
            "GRAPH" => graph_file = t[1].to_string(),
            "START" => start = t[1].parse().unwrap(),
            "NUMSTATES" => num_states = t[1].parse().unwrap(),
            "FINAL" => finals.push((t[1].parse().unwrap(), pf32(t[2]))),
            "ARC" => arcs.push((
                t[1].parse().unwrap(),
                t[2].parse().unwrap(),
                t[3].parse().unwrap(),
                pf32(t[4]),
                t[5].parse().unwrap(),
            )),
            "FRAMES" => {} // dimensions are re-derived from EMIT rows
            "EMIT" => {
                // EMIT <frame> v0 v1 ...
                let row: Vec<f32> = t[2..].iter().map(|s| pf32(s)).collect();
                emission.push(row);
            }
            "BEST" => {
                let score = pf32(t[1]);
                let words: Vec<u32> = t[2..].iter().map(|s| s.parse().unwrap()).collect();
                best = (score, words);
            }
            "NBEST" => {
                let score = pf32(t[1]);
                let words: Vec<u32> = t[2..].iter().map(|s| s.parse().unwrap()).collect();
                nbest.push((score, words));
            }
            other => panic!("unknown fixture directive `{other}`"),
        }
    }
    Expected {
        graph_file,
        start,
        num_states,
        finals,
        arcs,
        emission,
        best,
        nbest,
    }
}

/// The three committed fixtures.
const FIXTURES: [&str; 3] = ["linear", "epsilon", "nbest"];

fn load(name: &str) -> (Vec<u8>, Expected) {
    let dir = fixtures_dir();
    let exp = std::fs::read_to_string(dir.join(format!("{name}.expected")))
        .unwrap_or_else(|e| panic!("read {name}.expected: {e}"));
    let expected = parse_expected(&exp);
    let bytes = std::fs::read(dir.join(&expected.graph_file))
        .unwrap_or_else(|e| panic!("read {}: {e}", expected.graph_file));
    (bytes, expected)
}

/// (a) The reader reconstructs the OpenFST binary's structure exactly (T06).
#[test]
fn reader_reproduces_openfst_structure() {
    for name in FIXTURES {
        let (bytes, exp) = load(name);
        let fst = read_openfst_vector(&bytes).unwrap_or_else(|e| panic!("[{name}] reader: {e:?}"));

        assert_eq!(fst.start(), Some(exp.start), "[{name}] start");
        assert_eq!(fst.num_states(), exp.num_states, "[{name}] num_states");

        // Finals (sorted) match.
        let mut got_finals: Vec<(u32, f32)> = (0..exp.num_states as u32)
            .filter(|&s| fst.is_final(s).unwrap())
            .map(|s| (s, fst.final_weight(s).unwrap().value()))
            .collect();
        got_finals.sort_by_key(|&(s, _)| s);
        let mut want_finals = exp.finals.clone();
        want_finals.sort_by_key(|&(s, _)| s);
        assert_eq!(got_finals.len(), want_finals.len(), "[{name}] #finals");
        for (g, w) in got_finals.iter().zip(&want_finals) {
            assert_eq!(g.0, w.0, "[{name}] final state");
            assert!(
                (f64::from(g.1) - f64::from(w.1)).abs() <= STRUCT_ATOL,
                "[{name}] final weight {} vs {}",
                g.1,
                w.1
            );
        }

        // Arcs (sorted) match.
        let mut got_arcs: Vec<(u32, u32, u32, f32, u32)> = Vec::new();
        for s in 0..exp.num_states as u32 {
            for a in fst.arcs_of(s).unwrap() {
                got_arcs.push((s, a.ilabel, a.olabel, a.weight.value(), a.nextstate));
            }
        }
        let key = |a: &(u32, u32, u32, f32, u32)| (a.0, a.1, a.2, a.4);
        got_arcs.sort_by_key(key);
        let mut want_arcs = exp.arcs.clone();
        want_arcs.sort_by_key(key);
        assert_eq!(got_arcs.len(), want_arcs.len(), "[{name}] #arcs");
        for (g, w) in got_arcs.iter().zip(&want_arcs) {
            assert_eq!(
                (g.0, g.1, g.2, g.4),
                (w.0, w.1, w.2, w.4),
                "[{name}] arc topo"
            );
            assert!(
                (f64::from(g.3) - f64::from(w.3)).abs() <= STRUCT_ATOL,
                "[{name}] arc weight {} vs {}",
                g.3,
                w.3
            );
        }
    }
}

/// (b) + (c) Best-path word sequence is EXACT; score is within the honest atol.
#[test]
fn best_path_matches_openfst() {
    let mut max_delta = 0.0f64;
    for name in FIXTURES {
        let (bytes, exp) = load(name);
        let fst = read_openfst_vector(&bytes).unwrap();
        let hyp = WfstDecoder::new(&fst)
            .decode(&exp.emission)
            .unwrap_or_else(|e| panic!("[{name}] decode: {e:?}"))
            .unwrap_or_else(|| panic!("[{name}] no complete path"));

        // (b) EXACT word match.
        assert_eq!(hyp.words, exp.best.1, "[{name}] best-path words");

        // (c) score within the honest float-accumulation bound.
        let delta = (f64::from(hyp.score) - f64::from(exp.best.0)).abs();
        max_delta = max_delta.max(delta);
        assert!(
            delta <= SCORE_ATOL,
            "[{name}] best score {} vs OpenFST {} — delta {delta:.3e} exceeds atol {SCORE_ATOL:.3e}",
            hyp.score,
            exp.best.0
        );
    }
    // Greppable measured tightness (feedback-honest-parity-atol): shows how far
    // the actual delta sits below the architectural bound.
    println!("WFST_SCORE_DELTA best_path max |Δ| = {max_delta:.3e} (atol {SCORE_ATOL:.3e})");
}

/// (d) N-best set matches OpenFST: same word sequences in best-first order,
/// scores within the honest atol.
#[test]
fn nbest_matches_openfst() {
    let mut max_delta = 0.0f64;
    for name in FIXTURES {
        let (bytes, exp) = load(name);
        let fst = read_openfst_vector(&bytes).unwrap();
        let n = exp.nbest.len();
        let got = WfstDecoder::new(&fst)
            .n_best(n)
            .decode_nbest(&exp.emission)
            .unwrap_or_else(|e| panic!("[{name}] nbest: {e:?}"));

        assert_eq!(got.len(), exp.nbest.len(), "[{name}] n-best count");
        for (i, (g, (score, words))) in got.iter().zip(&exp.nbest).enumerate() {
            assert_eq!(&g.words, words, "[{name}] n-best[{i}] words");
            let delta = (f64::from(g.score) - f64::from(*score)).abs();
            max_delta = max_delta.max(delta);
            assert!(
                delta <= SCORE_ATOL,
                "[{name}] n-best[{i}] score {} vs {} — delta {delta:.3e} > atol {SCORE_ATOL:.3e}",
                g.score,
                score
            );
        }
        // Best-first: non-decreasing scores.
        for w in got.windows(2) {
            assert!(
                w[0].score <= w[1].score + SCORE_ATOL as f32,
                "[{name}] n-best order"
            );
        }
    }
    println!("WFST_SCORE_DELTA nbest max |Δ| = {max_delta:.3e} (atol {SCORE_ATOL:.3e})");
}
